"use strict";parserFactory.register("shw5.cc",()=>new Shw5Parser),parserFactory.register("bqka.cc",()=>new Shw5Parser);class Shw5Parser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("div.listmain");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("#chaptercontent")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"a.ll, a.rr"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".cover")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".intro")]}}